sql:
SELECT COUNT(DISTINCT user_id) 
FROM access_logs 
WHERE graph_id IN (SELECT graph_id FROM graphs WHERE is_public = 1);

SELECT created_at
FROM graphs
WHERE graph_id = 1;

SELECT algorithm_id, SUM(opttime) AS total_optimization_time
FROM optimization_results
GROUP BY algorithm_id;

SELECT * 
FROM optimization_results
WHERE algorithm_id = 1;

SELECT DISTINCT users.user_name
FROM users
JOIN graphs ON users.user_id = graphs.uploader_id;

SELECT graph_id, nodes
FROM graphs
ORDER BY nodes DESC;

SELECT result_id, graph_id, opttime, work, nodes_visited, result_description
FROM optimization_results
WHERE opttime > 4 AND work > (SELECT AVG(work) FROM optimization_results);

